var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"역시 봉인 사슬과 잔해의 상성은 좋지 않군.","JPN":"やはり封印の鎖と残骸の相性は良くないな。","ENG":"As expected, the Remains are no match against the Sealing Chain.","TWN":"果然封印鎖鏈對殘骸有克制作用。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……어쩔 수 없나?","JPN":"……仕方ないか。","ENG":"…We can't help it.","TWN":"……沒有辦法嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"여기는 철학부. 파편 회수 임무는 실패다. 작전 포인트까지 퇴각한다.","JPN":"こちら、哲学部。破片回収任務は失敗だ。作戦ポイントまで退却する。","ENG":"This is the Department of Philosophy. Mission to retrieve the Fragment failed. Retreating back to the operation point.","TWN":"這裡是哲學院，碎片回收任務失敗。我們將撤退到作戰點。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"모두 연막탄을 살포해! 퇴각한다!","JPN":"みんな、煙幕を使え！　退散だ！","ENG":"Use the smokescreens and retreat!","TWN":"放煙霧彈！撤退！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 자식이 어딜 도망치려고!","JPN":"させるかよ！","ENG":"Where do you think you're going?!","TWN":"喂！可惡！這些傢伙要跑了！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……콜록! 콜록!","JPN":"……ゲホッ！　ゲホッ！","ENG":"...*Cough!* *Cough!*","TWN":"……咳咳！咳咳！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참, 튀려면 그냥 튈 것이지 무슨 연막까지 뿌리고 난리야?","JPN":"ったく、大人しく逃げればいいのに、煙幕ってやりすぎだろ？","ENG":"Blimey, what's with the smokescreens? They could've just run away!","TWN":"真是的，想跑就跑，丟什麼煙霧彈？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"괘, 괜찮으세요?","JPN":"だ、大丈夫ですか？","ENG":"A-are you all right?","TWN":"你，你沒事吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저…… 그러니까, 으음.","JPN":"あの……えっと、あの……","ENG":"I... Um, w-well...","TWN":"我……那個，沒事。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"신경 쓰지 마. 어차피 놔주는 것까지가 작전이니까.","JPN":"気にするな。どうせ逃がしてやるところまでが作戦だからな。","ENG":"Don't mind me. It was part of the plan to let them go anyway.","TWN":"別在意，反正故意放他們走也是作戰中的一部分。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 작전…… 이라고요?","JPN":"え？　作戦……ですか？","ENG":"Huh? Did you say... plan?","TWN":"什麼？作戰……嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무튼 그런 게 있어. 그보다 너!","JPN":"そういうこと。それより、お前！","ENG":"Nothing you should be concerned about. But you!","TWN":"總之，我自有想法。倒是你啊——！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 네!","JPN":"はい？　あっ、はい！","ENG":"Huh? Yes?!","TWN":"啊？是！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당장 아카데미로 돌아가.","JPN":"今すぐアカデミーに戻れ。","ENG":"Go back to the Academy right now.","TWN":"馬上給我回學院。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"돌아가서 거기 이사장한테 오늘 있었던 일 하나도 빠짐없이 말하고, 보호 요청해.","JPN":"戻ってそこの理事長に今日の出来事を全部話して、保護を要請しろ。","ENG":"Go back and tell the chairwoman everything that just happened in detail, then ask for protection.","TWN":"回去後向理事長一五一十地說明今天發生的事，並且申請保護。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 당분간 아카데미 밖으로 한 발짝도 나오지 마. 알겠어?","JPN":"それからしばらくはアカデミーの外に一歩も出ないこと。いいな？","ENG":"Also, don't you ever think about setting foot outside of school grounds for a while, you hear me?","TWN":"還有，暫時不要離開學院一步，明白了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"네? 네에?","JPN":"え？　ええっ？","ENG":"Huh? What?","TWN":"嗯？什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터 아카데미는 그라운드 원에서 관리국 본부 다음으로 안전한 곳이야.","JPN":"カウンターアカデミーはグラウンド・ワンの中で管理局の次に安全なところだ。","ENG":"Counter Academy is the safest place to be in Ground One, right after the Administration headquarters.","TWN":"制裁者學院的安全程度在G1裡僅次於管理局總部。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"할배는 우리가 해줄 수 있는 게, <color=#ffd34c>거기까지</color>라고 했어.","JPN":"ジジイは俺たちができるのは、<color=#ffd34c>そこまで</color>だと言ってた。","ENG":"The old chap said that <color=#ffd34c>this is as far as we go</color>.","TWN":"老頭說，我們能為你做的，就<color=#ffd34c>只有這些</color>了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저, 궁금한 건 많지만…….","JPN":"あの、気になることが沢山あるんですけど……","ENG":"I... have a lot of questions, but...","TWN":"那個，我有很多疑問……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어떻게 제가 아카데미 편입생이라는 걸 알고 계셨어요? 그건 제 친구들 밖에 모를 텐데?","JPN":"私がアカデミーの編入生だって、なんで知ってるんですか？　これは私の友だちしか知らないはずです。","ENG":"How did you know I transferred to the Academy? That's only something my friends know.","TWN":"你怎麼知道我是學院插班生？除了我朋友之外應該沒人知道的？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시, 시끄러워!","JPN":"う、うるせえ！","ENG":"Sh-shut it!","TWN":"吵，吵死了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아무튼 나중에 후회하지 말고, 내 말대로 하라구!","JPN":"とにかく、後で後悔しないで、俺の言うとおりにやれ！","ENG":"Anyway, just do as I say or you might regret it later!","TWN":"總之以後不想後悔的話，就照我的話去做！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"저, 저기! 잠시만요!","JPN":"あ、あの！　待ってください！","ENG":"U-um! Wait!","TWN":"那，那個！等一下！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"전 아직 고맙다는 말, 못 했는데…….","JPN":"私はまだありがとうって、言えてないのに……","ENG":"I didn't get to thank you yet...","TWN":"我還沒來得及說聲謝謝呢……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하하하하하하하핫!","JPN":"はははははははははっ！","ENG":"Hah hah hah hah hah hah hah hah!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네, 레이디를 대하는 매너가 영 꽝이구만. 애송이 버넷.","JPN":"君、レディーに対するマナーがなってないね。バーネットの小僧。","ENG":"You really don't know how to treat a lady, eh? Kid Burnett.","TWN":"你對待女士的風度也太差勁了，小鬼伯內特。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하늘에 계신 버넷 형님도 손자가 이런 숙맥이라는 걸 알게 되면, 대성통곡을 하시겠어!","JPN":"天国にいるバーネットも、孫がこんな照れ屋だなんて知れば嘆き悲しむだろう！","ENG":"If Sir Burnett knew that his grandson was a sucker, he'd turn over in his grave!","TWN":"在天上的伯內特大哥要是知道孫子是這種傻瓜，應該會大哭一場吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그만 웃으라고! 이 망할 할배!","JPN":"笑うんじゃねぇ！　このクソジジイ！","ENG":"Stop making fun of me! You rotten old chap!","TWN":"別笑了！死老頭！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 애송이든, 버넷이든 둘 중 하나만 하란 말이야!","JPN":"あと小僧かバーネットか、どっちか一つにしろよ！","ENG":"It's either kid or Burnett! But not both!","TWN":"還有，要麼叫小鬼，要麼叫伯內特，二個選一個啦！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하하, 그건 앞으로 자네 하는 거 보고 차차 결정하지. 애송이 버넷.","JPN":"ははは、それはこれからの君の行動を見て決めることにしよう。バーネットの小僧。","ENG":"Hah hah hah! I'll let you know my decision after seeing how you do, kid Burnett.","TWN":"哈哈哈，那個就看你以後的表現，然後再慢慢決定吧，小鬼伯內特。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"으으, 됐어. 말을 말지, 말을 말아.","JPN":"うう、もういいぜ。","ENG":"Ugh, forget it. I'm done talking to you.","TWN":"呃呃，算了，我不該和你對話的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서? 작전은 어떻게 됐어? 다음은 어딜 들쑤시면 되는데?","JPN":"で？　作戦はどうなった？　次に暴れる場所はどこだ？","ENG":"So? How'd the operation go? What's the next move?","TWN":"然後呢？作戰怎麼樣了？接下來要去教訓誰？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭔, 젊은이가 성격이 그렇게 급한가?","JPN":"若造のくせにせっかちだな。","ENG":"What's the rush, young man?","TWN":"年輕人的脾氣怎麼那麼暴躁？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네도 알다시피, 레지나 맥크레디가 학회장으로 등극한 뒤 대대적인 숙청이 있었다네.","JPN":"君も知ってのとおり、レジーナ・マクレディーが学会長になって大々的な粛清が行われた。","ENG":"As you already know, after Regina MacCready became President, there was a massive purge.","TWN":"你也知道，蕾佳娜當上學會長之後，有過一次大規模的肅清。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 쥐를 몰 때는 너무 궁지에 몰리게 만들어서는 안 돼.","JPN":"だが、ネズミを追いつめる時に深追いは禁物だ。","ENG":"But you shouldn't corner a rat too much.","TWN":"但是，趕老鼠的時候，不能逼得太緊。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜냐하면 잃을 게 없어져 버린 쥐새끼들은 눈에 뵈는 게 없어지기 마련이거든.","JPN":"失うものがなくなったネズミは、我を失うからな。","ENG":"Because if they have nothing to lose, they are bound to act recklessly.","TWN":"老鼠急了也是會咬人的。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알고 있어. 그래서 우리가 이 꼴인 거잖아.","JPN":"わかってる。だから俺たちはこんな有り様なんだろ？","ENG":"I know that. That's why we're in this state.","TWN":"我知道，所以我們才會變成這樣不是嗎？"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"옳지. 신호가 잡혔어. 자네가 부착한 발신기는 잘 작동하고 있군.","JPN":"よし。信号を捉えた。君が付けた発信機はちゃんと作動しているな。","ENG":"Okay. We got a signal. The transmitter you put on them is working well.","TWN":"很好，有訊號了。你安裝的發信器沒什麼問題。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"레이디 다루는 법은 몰라도, 요원 장비는 그럭저럭 잘 다루게 되었어.","JPN":"レディーを扱う方法は知らなくても、エージェントの装備はそれなりに扱えるようになったか。","ENG":"You might not know how to treat a lady, but you've become more familiar with agent gear.","TWN":"雖然不懂得怎麼對待女士，但對裝備還蠻有兩下子的。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"슬슬 준비하게.","JPN":"そろそろ準備してくれ。","ENG":"Get ready.","TWN":"該準備了。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"쥐새끼가 쥐구멍으로 돌아가면, 녀석들을 뒤쫓아 철학부 근거지를 일망타진한다.","JPN":"ネズミが穴に戻ったら、やつらを追いかけて哲学部の本拠地を一網打尽にする。","ENG":"Once the rat goes into its hole, we follow them to the Department of Philosophy's base and make a sweeping arrest.","TWN":"等老鼠回到洞裡，我們就出發，然後將哲學院的巢穴一網打盡。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"왜 벌레 씹은 표정을 하고 있나, 애송이 버넷?","JPN":"何を渋い顔してるんだ、バーネットの小僧。","ENG":"What's with the sour face, kid Burnett?","TWN":"你怎麼還臭著張臉，小鬼伯內特？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……마음에 안 들어.","JPN":"……気に入らねえ。","ENG":"...I don't like it.","TWN":"……我不喜歡這樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잔당 녀석들을 처리하는 건 분리수거 같은 거라고 쳐. 어차피 누군가는 해야 하니까.","JPN":"残党を処理するところまでは、理解できる。どうせ誰かはやらなきゃだしな。","ENG":"I get why we're cleaning out the rump of that group, because someone has to do it.","TWN":"處理餘黨的活我就當作是分類回收垃圾了，反正總得有人做。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그 리온이라는 앤 정말 괜찮은 거야?","JPN":"だけど、あのリオンって子は本当に大丈夫なのか？","ENG":"But that Liona girl, will she be all right?","TWN":"但那個叫萊恩的女生就這麼不管了嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 애는 자기가 다루는 게 마왕의 파편이라는 것조차 모르고 있었다고.","JPN":"あの子、自分の持ち物が魔王の破片ってことすら知らなかったんだ。","ENG":"I mean, she didn't even realise she was handling a Fragment of the Demon Lord.","TWN":"她根本不知道自己手裡的那個是魔王的碎片。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 생각을 하나 했더니, 설마 임무에 사적인 감정을 품은 건가?","JPN":"何を考えているのかと思ったら、まさか任務に私情を挟んでいるのか？","ENG":"Is this what you were thinking about? You're not bringing personal feelings to the mission, are you?","TWN":"我還以為你在想什麼呢，你不會是在任務中摻雜了私人感情吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그딴 거 아니거든!","JPN":"そんなんじゃねえよ！","ENG":"You know that's not it!","TWN":"才不是那樣的！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 아이에게 <color=#ffd34c>세상의 진실</color>을 알려주면 뭐가 달라지지?","JPN":"あの子に<color=#ffd34c>世界の真実</color>を教えて何が変わる？","ENG":"What difference does it make if you tell that child <color=#ffd34c>the truth about the world</color>?","TWN":"告訴那個孩子<color=#ffd34c>世界的真相</color>，會有什麼不同嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"때때로 아무것도 모르는 게 약일 수도 있어.","JPN":"時には知らないほうがいいことだってあるだろう。","ENG":"Sometimes, ignorance is bliss.","TWN":"有時候什麼都不知道才是最好的解藥。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 마왕의 파편이라는 걸 알게 된다면, 그 아이의 인생은 틀림없이 요동치게 될 거야.","JPN":"あれが魔王の破片だと知れば、あの子の人生はきっと波乱なものになる。","ENG":"If she finds out that it's a Fragment of the Demon Lord, it will shake her world.","TWN":"如果讓她知道那是魔王的碎片，那個孩子的人生肯定會有翻天覆地的變化吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 아이가 원하든, 원치 않든 말이야.","JPN":"あの子が望んでも、望まなくてもな。","ENG":"Whether she wants it or not.","TWN":"不管她願意不願意。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서? 그냥 내버려 두자고? <color=#ffd34c>특별 관리 대상</color>이라면서?","JPN":"それで？　あのままほっとくのか？　<color=#ffd34c>特別管理対象</color>だって言っただろ？","ENG":"So? We just leave her like that? Didn't you say she was under <color=#ffd34c>special surveillance</color>?","TWN":"然後呢？就那麼放著不管嗎？不是說她是<color=#ffd34c>特別管理對象</color>嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네는 아무래도 특별 관리 대상이라는 뜻을 착각하고 있는 모양이군.","JPN":"君はどうやら特別管理対象の意味を勘違いしているようだ。","ENG":"It seems you're misunderstanding what special surveillance means.","TWN":"看來你對這個詞彙有什麼誤會。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관은 자네 생각처럼 정의의 사도의 모임이 아니야.","JPN":"機関は、君が思うような正義の使徒の集まりではない。","ENG":"The Institution isn't a group of people that brings justice like you think.","TWN":"機關不是像你想的那樣，是正義使者的聚會。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우린 미지의 아티팩트를 수색 및 보존 하며 그게 불가능할 경우에는 처분하지.","JPN":"俺たちは未知のアーティファクトを捜索および保存し、それが不可能な場合には処分する。","ENG":"We search for and safekeep unknown Artifacts, and if that is impossible, we discard them.","TWN":"我們會搜索並保存未知的人造神器，如果事與願違，則會選擇將其處理掉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"처분…… 이라고?","JPN":"処分……だと？","ENG":"Discard...?","TWN":"處理……？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"설마, 그럼 특별 관리 대상이라는 게……?","JPN":"まさか、じゃあ特別管理対象って……？","ENG":"Then, special surveillance means...","TWN":"難道，所謂的特別管理對象就是……？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"특별 관리 대상 17호…… 본명, <color=#ffd34c>리오나 하트</color>.","JPN":"特別管理対象17号……本名、<color=#ffd34c>リオナ・ハート</color>。","ENG":"Special surveillance No. 17... Name, <color=#ffd34c>Liona Hartt</color>.","TWN":"特別管理對象17號……本名，<color=#ffd34c>萊歐娜·哈特</color>。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"수년 전, 그녀는 학교 친구들과 함께 버스를 타고 이동하던 중에 봉변을 당했지.","JPN":"数年前、彼女は学校の友だちとともにバスに乗っていたところ不慮の事故にあった。","ENG":"A few years ago, she and her friends got into a freak accident while on the bus.","TWN":"多年前，她和同學一起坐公車時，在移動中遭遇了意外。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"표면적으로 그 사건은 단순한 침식 사태라고 보도되었지만…….","JPN":"表向きではあの事件は、単なる侵食事態だと報道されたが……","ENG":"On the surface, the incident was reported as a Corruption disaster...","TWN":"雖然表面上報導稱那次事件只是單純的侵蝕事件……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"사실, 그건 학회가 연구 중이었던 파편이 운송 중에 폭주하여 발생한 사고였어.","JPN":"あれは、実は学会が研究していた破片が運送途中に暴走して起きた事故だったのだ。","ENG":"but the truth is that the incident occurred because the Fragment the Society was researching had an outburst during transportation.","TWN":"事實上，那是學會正在研究的碎片在運輸過程中失控引發的事故。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"원래라면 그보다 열 배 이상의 사상자를 낼 뻔한 사고를, 리오나는 혼자 막아냈지.","JPN":"本来なら10倍以上の死傷者が生じるところだった事故を、リオナは一人で止めて見せた。","ENG":"Originally, the incident could've ended up with ten times the casualties, but Liona stopped it on her own.","TWN":"本來是險些造成十倍以上傷亡的事故，但被萊歐娜獨自一人擋住了。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 그 대가로 파편은 그녀의 기억을 양분 삼아 자의식을 획득했네.","JPN":"だがその代償として、破片は彼女の記憶を養分に自我を得た。","ENG":"But in return, the Fragment gained self-consciousness by consuming her memories.","TWN":"但作為代價，碎片以她的記憶為養分，獲得了自我意識。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"쉽게 말하면, 리오나 하트의 생명줄은 그 파편이 쥐고 있다는 뜻이야.","JPN":"わかりやすく言うと、リオナ・ハートの命をあの破片が握っているということだ。","ENG":"In other words, Liona Hartt's life depends on that Fragment.","TWN":"簡單地說，萊歐娜·哈特的性命就掌握在那塊碎片之中。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"자의식을 획득했다고?","JPN":"自我だと？","ENG":"Has it gained self-consciousness?","TWN":"獲得了自我意識？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지식의 호수는…… 하나이자 전체. 전체이자 하나.","JPN":"知識の湖は……一つであり全て。全てであり一つ。","ENG":"The Lake of Knowledge is... one and all. All and one.","TWN":"知識湖水……既是一體也是全部，既是全部也是一體。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네도 알다시피, 가아그셰블라는 하나의 마왕이자 동시에 군집하는 정보 집합체지.","JPN":"君も知っているように、ガアグシェブラは魔王であると同時に群集する情報の集合体だ。","ENG":"As you know, Gha'agsheblah is a Demon Lord, but also a hive of information.","TWN":"你也知道，加格舍夫拉是魔王，同時也是成群的資訊集合體。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 LAKE-4에 봉인된 거대 파편을 떠올려보게.","JPN":"だが、LAKE-4に封印された巨大な破片を思い出してみろ。","ENG":"But think back to the colossal Fragment that was sealed in LAKE-4.","TWN":"但是，你想想被封印在LAKE-4的巨大碎片。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"집합체의 크기가 아무리 커도, 우리는 그걸 파편이라고 부르지 마왕이라 부르진 않아.","JPN":"集合体がいくら大きくても、俺たちはそれを破片とは呼んでも魔王とは呼ばない。","ENG":"No matter how massive the hive is, we call it a \\"Fragment,\\" not a Demon Lord.","TWN":"無論集合體有多大，我們都叫它碎片，而不是魔王。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 자의식을 획득한 파편이라는 게…… 마왕이 될 수도 있다는 거야?","JPN":"じゃあ、自我を得た破片が……魔王になることもあるってことか？","ENG":"Then, you're telling me that a Fragment that gains self-consciousness... can become a Demon Lord?","TWN":"你是說，獲得自我意識的碎片……有可能成為魔王？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어디까지나 가설의 영역이야.","JPN":"あくまでも仮説の領域だがな。","ENG":"It is all hypothetical.","TWN":"這些都是假設。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇지만 그것이 단일 개체가 아닌, 집합체라면 충분히 가능성 있는 가설이지.","JPN":"だがそれが単一個体ではなく、集合体なら十分あり得る仮説だ。","ENG":"However, it is a plausible hypothesis if it's a hive rather than a single entity.","TWN":"但如果它是一個集合體，而不是單一的個體，那這個假設便是完全有可能實現的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서? 그 애가 그렇게 된 건 사고에 휘말렸기 때문이라면서?","JPN":"で？　あの子がそうなったのは事故に巻き込まれたからだろ？","ENG":"So? She's like that because she got caught up in the accident, right?","TWN":"所以呢？你不是說她變成那個樣子，是因為被捲入了事故嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 피해자잖아!","JPN":"じゃあ、被害者じゃないか！","ENG":"Then, she's just a victim!","TWN":"那她不就是受害者嗎！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잘못한 게 없어도, 마왕이 될 가능성이 있으니까 죽을 때까지 감시하겠다고?","JPN":"何も悪いことなんてしてないのに、魔王になる可能性があるから死ぬまで監視するつもりだっていうのか？","ENG":"She's done nothing wrong, but she's under surveillance until she dies because she might turn into a Demon Lord?","TWN":"就算她沒有做錯什麼，也要監視她到她死為止，就因為她有可能成為魔王嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"죽을 때까지? 누가 죽을 때까지 기다린 다는 거지, 애송이?","JPN":"死ぬまで？　誰が死ぬまで待つと言ったんだ、小僧。","ENG":"Until she dies? Who said anything about waiting until her death, kid?","TWN":"監視她到她死為止？誰有這個美國時間，小鬼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"저 아이가 죽으면 곤란해. 연결된 파편이 폭주할 가능성이 커지니까.","JPN":"あの子に死なれては困る。繋がっている破片が暴走する可能性が高くなるからな。","ENG":"It'll be become a problem if she dies. It's highly likely the connected Fragment will cause another outburst.","TWN":"那孩子死了可不好辦，因為連接的碎片暴走的可能性會增大。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"만에 하나라도 파편이 폭주할 조짐을 보이면 즉시 연명조치 후 봉인할 걸세.","JPN":"万が一にでも破片が暴走する兆しを見せれば、即座に延命措置を施し封印する。","ENG":"If the Fragment shows any signs of an outburst, we will immediately sustain her life and seal it.","TWN":"萬一出現碎片暴走的徵兆，就要立即對她採取延長生命的措施，並進行封印。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"절대로 깨어나지 않도록. 자네가 쥐고 있는 그 봉인 사슬로 말이야.","JPN":"決して目覚めないように。君が持っているその封印の鎖でな。","ENG":"So she never wakes up. With that Sealing Chain you're holding at that.","TWN":"確保她絕對不要醒來。就用你手上的那個封印鎖鏈。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"연명 조치 후 봉인?","JPN":"延命措置の後に封印？","ENG":"Sustain her life and seal it?","TWN":"採取延長生命的措施然後封印起來？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"웃기지마, 할배! 그게 식물인간을 만들겠다는 소리랑 뭐가 달라?","JPN":"ふざけんなよ、ジジイ！　それってつまり、植物人間にするって意味だろ！","ENG":"Don't make me laugh, old chap! How's that any different from putting her into a vegetable state?!","TWN":"說笑嗎，老頭！那跟成為植物人有什麼不同？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 그딴 미친 짓거리에 협력할 것 같아!?","JPN":"俺はそんなことに協力しない！","ENG":"You think I'm gonna cooperate with something as crazy as that?!","TWN":"你以為我會配合你發瘋嗎？！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼, 자네가 리오나 하트를 위해 무엇을 할 수 있지?","JPN":"では、君はリオナ・ハートのために何ができる？","ENG":"Then, what else can you do for Liona Hartt?","TWN":"那麼，你能為萊歐娜·哈特做什麼？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 아이와 파편을 강제로 떨어트려 놓기라도 할 텐가?","JPN":"あの子と破片を強制的に引き離すつもりか？","ENG":"Are you going to force her and the Fragment apart?","TWN":"你想強行把那孩子和碎片分開嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그러다 파편이 폭주하면? 수백, 수천 단위의 목숨을 자네가 감당할 수 있나?","JPN":"それで破片が暴走したら？　数百、数千の命の責任が君に負えるのか？","ENG":"But what if the Fragment has an outburst? Will you take responsibility for the hundreds and thousands of lives it kills?","TWN":"如果碎片暴走了怎麼辦？成百上千條的生命，你好好想想，到時候要算在誰的頭上？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……큭.","JPN":"くっ……。","ENG":"...Krgh.","TWN":"……嘖。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에게 인정받고 싶다면, 헛된 망상부터 집어치워. 애송이.","JPN":"機関に認めてもらいたいなら、儚い妄想は捨てろ。小僧。","ENG":"If you want to be recognized by the Institution, stop your daydreaming, kid.","TWN":"要想得到機關的認可，就先別胡思亂想了，小鬼。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우린 모두를 구할 수 있는 정의의 사도 같은 게 아니야.","JPN":"俺たちはみんなを助けられる正義の使徒などではない。","ENG":"We are not heroes of justice who can save everybody.","TWN":"我們不是什麼可以拯救所有人的正義使者。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트 게임에서도 우리는, 우리 스스로의 사명보다 게임을 택했네.","JPN":"クリフォトゲームでも俺たちは、自らの使命よりゲームを選んだ。","ENG":"Even in the Qliphoth Game, we chose the game instead of our own mission.","TWN":"在逆卡巴拉遊戲裡也是，比起自己的使命，我們選擇了遊戲。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 같은 평범한 인간들이 마왕에게 대적하기 위해서는.","JPN":"俺たちのような普通の人間が魔王の相手をするためには。","ENG":"For ordinary people like us to fight against a Demon Lord,","TWN":"我們這些凡夫俗子，想要對付魔王……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"목숨을 저울질해가면서 더 효율적인 선택지를 고를 수밖에 없다는 걸 받아들이게.","JPN":"命を天秤にかけながらより効率的な道を選ぶしかいないということを受け入れろ。","ENG":"you have to accept that we have to weigh lives and choose the more efficient option.","TWN":"在權衡生命的時候，就只能接受更有效率的選項。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>파편이 폭주하기 직전까지 아무것도 모른 채, 일상을 누리는 것.</color>","JPN":"<color=#ffd34c>破片が暴走する直前までは何も知らないまま、日常を過ごすこと。</color>","ENG":"<color=#ffd34c>Enjoying her ordinary days until the Fragment has an outburst.</color>","TWN":"<color=#ffd34c>在碎片暴走之前，可以什麼不知道地享受日常生活。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관이 리오나 하트에게 베풀 수 있는 배려는 <color=#ffd34c>거기까지</color>야.","JPN":"機関がリオナ・ハートにできる配慮は<color=#ffd34c>そこまで</color>だ。","ENG":"That is where the Institution's care for Liona Hartt <color=#ffd34c>stops</color>.","TWN":"機關能給萊歐娜·哈特的關懷就<color=#ffd34c>只有這些</color>了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……웃기지 마.","JPN":"……ふざけんな。","ENG":"...Don't make me laugh.","TWN":"……別開玩笑了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 건……! 그냥 비겁한 변명일 뿐이잖아……!","JPN":"そんなの……！　ただの卑怯な言い訳だろ……！","ENG":"That's...! That's just a coward's excuse...!","TWN":"那些……！不就是卑鄙的藉口嗎……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"동감이야, 애송이. 하지만 동시에 냉정한 현실이기도 하지.","JPN":"同感だ、小僧。だがこれは、同時に厳しい現実でもある。","ENG":"I agree, kid. But it is also the cold harsh truth.","TWN":"我也有同感，小鬼，但同時這也是冷酷的現實。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"적어도, 지금의 기관으로서는 말이야.","JPN":"少なくとも、今の機関としてはな。","ENG":"At least, that is the truth about the current state of the Institution.","TWN":"至少，對現在的機關來說便是如此。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};